import{_ as t,o as a,c as r,ae as o}from"./chunks/framework.BGHOrOyn.js";const m=JSON.parse('{"title":"ESP32 CAM","description":"","frontmatter":{},"headers":[],"relativePath":"microcontrollers-and-socs/esp32/esp32-cam.md","filePath":"microcontrollers-and-socs/esp32/esp32-cam.md"}'),i={name:"microcontrollers-and-socs/esp32/esp32-cam.md"};function s(n,e,l,p,d,h){return a(),r("div",null,[...e[0]||(e[0]=[o(`<h1 id="esp32-cam" tabindex="-1">ESP32 CAM <a class="header-anchor" href="#esp32-cam" aria-label="Permalink to &quot;ESP32 CAM&quot;">​</a></h1><h2 id="esp32-cam-video-streaming-and-face-recognition-with-arduino-ide" tabindex="-1">ESP32-CAM Video Streaming and Face Recognition with Arduino IDE <a class="header-anchor" href="#esp32-cam-video-streaming-and-face-recognition-with-arduino-ide" aria-label="Permalink to &quot;ESP32-CAM Video Streaming and Face Recognition with Arduino IDE&quot;">​</a></h2><p>This article is a quick getting-started guide for the ESP32-CAM board. We’ll show you how to setup a video streaming web server with face recognition and detection in less than 5 minutes with Arduino IDE.</p><figure><img src="https://i0.wp.com/randomnerdtutorials.com/wp-content/uploads/2019/03/ESP32-CAM-getting-started.jpg?resize=828%2C466&amp;quality=100&amp;strip=all&amp;ssl=1" alt="" height="448" width="796"><figcaption></figcaption></figure><p><strong>Note:</strong> in this tutorial we use the example from the arduino-esp32 library. This tutorial doesn’t cover how to modify the example.</p><p><strong>Related project:</strong> <a href="https://randomnerdtutorials.com/esp32-cam-video-streaming-web-server-camera-home-assistant/" target="_blank" rel="noreferrer">ESP32-CAM Video Streaming Web Server</a> (works with Home Assistant and Node-Red)</p><h3 id="watch-the-video-tutorial" tabindex="-1">Watch the Video Tutorial <a class="header-anchor" href="#watch-the-video-tutorial" aria-label="Permalink to &quot;Watch the Video Tutorial&quot;">​</a></h3><p>You can watch the video tutorial or keep reading this page for the written instructions.</p><h3 id="parts-required" tabindex="-1">Parts Required <a class="header-anchor" href="#parts-required" aria-label="Permalink to &quot;Parts Required&quot;">​</a></h3><p>To follow this tutorial you need the following components:</p><ul><li><a href="https://makeradvisor.com/tools/esp32-cam/" target="_blank" rel="noreferrer"><strong>ESP32-CAM with OV2640</strong></a> – read <a href="https://makeradvisor.com/esp32-camera-cam-boards-review-comparison/" target="_blank" rel="noreferrer">Best ESP32-CAM Dev Boards</a></li><li><a href="https://makeradvisor.com/tools/ftdi-programmer-board/" target="_blank" rel="noreferrer">FTDI programmer</a></li><li><a href="https://makeradvisor.com/tools/jumper-wires-kit-120-pieces/" target="_blank" rel="noreferrer">Female-to-female jumper wires</a></li></ul><p>You can use the preceding links or go directly to <a href="https://makeradvisor.com/tools/?utm_source=rnt&amp;utm_medium=post&amp;utm_campaign=post" target="_blank" rel="noreferrer">MakerAdvisor.com/tools</a> to find all the parts for your projects at the best price!</p><p><a href="https://makeradvisor.com/tools/?utm_source=rnt&amp;utm_medium=post&amp;utm_campaign=post" target="_blank" rel="noreferrer"><img src="https://i0.wp.com/randomnerdtutorials.com/wp-content/uploads/2017/10/header-200.png?w=828&amp;quality=100&amp;strip=all&amp;ssl=1" alt=""></a></p><h3 id="introducing-the-esp32-cam" tabindex="-1">Introducing the ESP32-CAM <a class="header-anchor" href="#introducing-the-esp32-cam" aria-label="Permalink to &quot;Introducing the ESP32-CAM&quot;">​</a></h3><figure><img src="https://i0.wp.com/randomnerdtutorials.com/wp-content/uploads/2019/03/ESP32-CAM-camera.jpg?resize=750%2C421&amp;quality=100&amp;strip=all&amp;ssl=1" alt="" height="421" width="750"><figcaption></figcaption></figure><p>The <a href="https://makeradvisor.com/tools/esp32-cam/" target="_blank" rel="noreferrer">ESP32-CAM</a> is a very small camera module with the ESP32-S chip that costs approximately $10. Besides the OV2640 camera, and several GPIOs to connect peripherals, it also features a microSD card slot that can be useful to store images taken with the camera or to store files to serve to clients.</p><figure><img src="https://i0.wp.com/randomnerdtutorials.com/wp-content/uploads/2019/03/esp32-can-labeled.jpeg?resize=627%2C350&amp;quality=100&amp;strip=all&amp;ssl=1" alt="" height="350" width="627"><figcaption><p><a href="https://www.seeedstudio.com/media/catalog/product/cache/ef3164306500b1080e8560b2e8b5cc0f/b/a/bazaar1003542_esp32cam2.jpg">Image source – Seeed Studio</a></p></figcaption></figure><p>The <a href="https://makeradvisor.com/tools/esp32-cam/" target="_blank" rel="noreferrer">ESP32-CAM</a> doesn’t come with a USB connector, so you need an <a href="https://makeradvisor.com/tools/ftdi-programmer-board/" target="_blank" rel="noreferrer">FTDI programmer</a> to upload code through the U0R and U0T pins (serial pins).</p><figure><img src="https://i0.wp.com/randomnerdtutorials.com/wp-content/uploads/2019/03/FTDI-programmer-ESP32-CAM.jpg?resize=750%2C421&amp;quality=100&amp;strip=all&amp;ssl=1" alt="" height="421" width="750"><figcaption></figcaption></figure><h3 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h3><p>Here is a list with the ESP32-CAM features:</p><ul><li>The smallest 802.11b/g/n Wi-Fi BT SoC module</li><li>Low power 32-bit CPU,can also serve the application processor</li><li>Up to 160MHz clock speed, summary computing power up to 600 DMIPS</li><li>Built-in 520 KB SRAM, external 4MPSRAM</li><li>Supports UART/SPI/I2C/PWM/ADC/DAC</li><li>Support OV2640 and OV7670 cameras, built-in flash lamp</li><li>Support image WiFI upload</li><li>Support TF card</li><li>Supports multiple sleep modes</li><li>Embedded Lwip and FreeRTOS</li><li>Supports STA/AP/STA+AP operation mode</li><li>Support Smart Config/AirKiss technology</li><li>Support for serial port local and remote firmware upgrades (FOTA)</li></ul><h3 id="esp32-cam-pinout" tabindex="-1">ESP32-CAM Pinout <a class="header-anchor" href="#esp32-cam-pinout" aria-label="Permalink to &quot;ESP32-CAM Pinout&quot;">​</a></h3><p>The following figure shows the ESP32-CAM pinout (AI-Thinker module).</p><p>There are three GND pins and two pins for power: either 3.3V or 5V.</p><p>GPIO 1 and GPIO 3 are the serial pins. You need these pins to upload code to your board. Additionally, GPIO 0 also plays an important role, since it determines whether the ESP32 is in flashing mode or not. When GPIO 0 is connected to GND, the ESP32 is in flashing mode.</p><p>The following pins are internally connected to the microSD card reader:</p><ul><li>GPIO 14: CLK</li><li>GPIO 15: CMD</li><li>GPIO 2: Data 0</li><li>GPIO 4: Data 1 (also connected to the on-board LED)</li><li>GPIO 12: Data 2</li><li>GPIO 13: Data 3</li></ul><h3 id="video-streaming-server" tabindex="-1">Video Streaming Server <a class="header-anchor" href="#video-streaming-server" aria-label="Permalink to &quot;Video Streaming Server&quot;">​</a></h3><p>Follow the next steps to build a video streaming web server with the ESP32-CAM that you can access on your local network.</p><p><strong>Important:</strong> Make sure you have your Arduino IDE updated as well as the latest version of the ESP32 add-on.</p><h4 id="_1-install-the-esp32-add-on" tabindex="-1">1. Install the ESP32 add-on <a class="header-anchor" href="#_1-install-the-esp32-add-on" aria-label="Permalink to &quot;1. Install the ESP32 add-on&quot;">​</a></h4><p>In this example, we use Arduino IDE to program the ESP32-CAM board. So, you need to have Arduino IDE installed as well as the ESP32 add-on. Follow one of the next tutorials to install the ESP32 add-on, if you haven’t already:</p><ul><li><a href="https://randomnerdtutorials.com/installing-the-esp32-board-in-arduino-ide-windows-instructions/" target="_blank" rel="noreferrer">Installing the ESP32 Board in Arduino IDE (Windows instructions)</a></li><li><a href="https://randomnerdtutorials.com/installing-the-esp32-board-in-arduino-ide-mac-and-linux-instructions/" target="_blank" rel="noreferrer">Installing the ESP32 Board in Arduino IDE (Mac and Linux instructions)</a></li></ul><h4 id="_2-camerawebserver-example-code" tabindex="-1">2. CameraWebServer Example Code <a class="header-anchor" href="#_2-camerawebserver-example-code" aria-label="Permalink to &quot;2. CameraWebServer Example Code&quot;">​</a></h4><p>In your Arduino IDE, go to <strong>File</strong> &gt; <strong>Examples</strong> &gt; <strong>ESP32</strong> &gt; <strong>Camera</strong> and open the <strong>CameraWebServer</strong> example.</p><figure><img src="https://i0.wp.com/randomnerdtutorials.com/wp-content/uploads/2019/03/esp32-cam-open-camerawebserver-example.png?resize=686%2C344&amp;quality=100&amp;strip=all&amp;ssl=1" alt="" height="344" width="686"><figcaption></figcaption></figure><p>The following code should load.</p><div data-full-width="true"><figure><img src="https://i0.wp.com/randomnerdtutorials.com/wp-content/uploads/2019/12/camera-web-server-example-code.png?resize=603%2C571&amp;quality=100&amp;strip=all&amp;ssl=1" alt="ESP32 CameraWebServer Example"><figcaption></figcaption></figure></div><p>Before uploading the code, you need to insert your network credentials in the following variables:</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> char*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ssid </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;REPLACE_WITH_YOUR_SSID&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> char*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> password </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;REPLACE_WITH_YOUR_PASSWORD&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>Then, make sure you select the right camera module. In this case, we’re using the AI-THINKER Model.</p><figure><img src="https://i0.wp.com/randomnerdtutorials.com/wp-content/uploads/2019/03/AI-Thinker-ESP32CAM.jpg?resize=750%2C421&amp;quality=100&amp;strip=all&amp;ssl=1" alt="" height="421" width="750"><figcaption></figcaption></figure><p>So, comment all the other models and uncomment this one:</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Select camera model</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//#define CAMERA_MODEL_WROVER_KIT</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//#define CAMERA_MODEL_ESP_EYE</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//#define CAMERA_MODEL_M5STACK_PSRAM</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//#define CAMERA_MODEL_M5STACK_WIDE</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">#</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"># define</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> CAMERA_MODEL_AI_THINKER</span></span></code></pre></div><p>If none of these correspond to the camera you’re using, you need to add the pin assignment for your specific board in the camera_pins.h tab.</p><p>Now, the code is ready to be uploaded to your ESP32.</p><h3 id="_3-esp32-cam-upload-code" tabindex="-1">3. ESP32-CAM Upload Code <a href="#mce_111" id="mce_111"></a> <a class="header-anchor" href="#_3-esp32-cam-upload-code" aria-label="Permalink to &quot;3. ESP32-CAM Upload Code &lt;a href=&quot;#mce_111&quot; id=&quot;mce_111&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>Connect the ESP32-CAM board to your computer using an FTDI programmer. Follow the next schematic diagram:</p><figure><img src="https://i0.wp.com/randomnerdtutorials.com/wp-content/uploads/2019/12/ESP32-CAM-FTDI-programmer-5V-supply.png?resize=750%2C333&amp;quality=100&amp;strip=all&amp;ssl=1" alt="" height="333" width="750"><figcaption></figcaption></figure><p>Many FTDI programmers have a jumper that allows you to select 3.3V or 5V. Make sure the jumper is in the right place to select 5V.</p><p><strong>Important:</strong> GPIO 0 needs to be connected to GND so that you’re able to upload code.</p><table tabindex="0"><thead><tr><th><strong>ESP32-CAM</strong></th><th><strong>FTDI Programmer</strong></th></tr></thead><tbody><tr><td>GND</td><td>GND</td></tr><tr><td>5V</td><td>VCC (5V)</td></tr><tr><td>U0R</td><td>TX</td></tr><tr><td>U0T</td><td>RX</td></tr><tr><td>GPIO 0</td><td>GND</td></tr></tbody></table><p>To upload the code, follow the next steps:</p><p>1) Go to <strong>Tools</strong> &gt; <strong>Board</strong> and select <strong>AI-Thinker ESP32-CAM</strong>.</p><p>2) Go to <strong>Tools</strong> &gt; <strong>Port</strong> and select the COM port the ESP32 is connected to.</p><p>3) Then, click the upload button to upload the code.</p><figure><img src="https://i0.wp.com/randomnerdtutorials.com/wp-content/uploads/2019/12/upload-button-arduino-ide.png?resize=32%2C32&amp;quality=100&amp;strip=all&amp;ssl=1" alt="" height="32" width="32"><figcaption></figcaption></figure><p>4) When you start to see these dots on the debugging window as shown below, press the ESP32-CAM on-board RST button.</p><figure><img src="https://i0.wp.com/randomnerdtutorials.com/wp-content/uploads/2019/12/dots-uploading-code.png?resize=828%2C75&amp;quality=100&amp;strip=all&amp;ssl=1" alt="" height="72" width="796"><figcaption></figcaption></figure><p>After a few seconds, the code should be successfully uploaded to your board.</p><h3 id="getting-the-ip-address" tabindex="-1">Getting the IP address <a class="header-anchor" href="#getting-the-ip-address" aria-label="Permalink to &quot;Getting the IP address&quot;">​</a></h3><p>After uploading the code, disconnect GPIO 0 from GND.</p><p>Open the Serial Monitor at a baud rate of 115200. Press the ESP32-CAM on-board Reset button.</p><p>The ESP32 IP address should be printed in the Serial Monitor.</p><figure><img src="https://i0.wp.com/randomnerdtutorials.com/wp-content/uploads/2019/03/esp32-cam-ip-address.png?resize=615%2C427&amp;quality=100&amp;strip=all&amp;ssl=1" alt="" height="427" width="615"><figcaption></figcaption></figure><h3 id="accessing-the-video-streaming-server" tabindex="-1">Accessing the Video Streaming Server <a class="header-anchor" href="#accessing-the-video-streaming-server" aria-label="Permalink to &quot;Accessing the Video Streaming Server&quot;">​</a></h3><p>Now, you can access your camera streaming server on your local network. Open a browser and type the ESP32-CAM IP address. Press the <strong>Start Streaming</strong> button to start video streaming.</p><figure><img src="https://i0.wp.com/randomnerdtutorials.com/wp-content/uploads/2019/03/ESP32-CAM-video-streaming-example.jpg?resize=750%2C407&amp;quality=100&amp;strip=all&amp;ssl=1" alt="" height="407" width="750"><figcaption></figcaption></figure><p>You also have the option to take photos by clicking the <strong>Get Still</strong> button. Unfortunately, this example doesn’t save the photos, but you can modify it to use the on board microSD Card to store the captured photos.</p><p>There are also several camera settings that you can play with to adjust the image settings.</p><p>Finally, you can do face recognition and detection.</p><figure><img src="https://i0.wp.com/randomnerdtutorials.com/wp-content/uploads/2019/03/ESP32-cam-intruder-alert.jpg?resize=750%2C411&amp;quality=100&amp;strip=all&amp;ssl=1" alt="" height="411" width="750"><figcaption></figcaption></figure><p>First, you need to enroll a new face. It will make several attempts to save the face. After enrolling a new user, it should detect the face later on (subject 0).<br></p><figure><img src="https://i0.wp.com/randomnerdtutorials.com/wp-content/uploads/2019/03/esp32-cam-face-recognition-detection.jpg?resize=750%2C391&amp;quality=100&amp;strip=all&amp;ssl=1" alt="" height="391" width="750"><figcaption></figcaption></figure><p>And that’s it. Now you have your video streaming web server up and running with face detection and recognition with the example from the library.</p><h3 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h3><p>If you’re getting any of the following errors, read our <a href="https://randomnerdtutorials.com/esp32-cam-troubleshooting-guide/" target="_blank" rel="noreferrer"><strong>ESP32-CAM Troubleshooting Guide: Most Common Problems Fixed</strong></a></p><ul><li>Failed to connect to ESP32: Timed out waiting for packet header</li><li>Camera init failed with error 0x20001 or similar</li><li>Brownout detector or Guru meditation error</li><li>Sketch too big error – Wrong partition scheme selected</li><li>Board at COMX is not available – COM Port Not Selected</li><li>Psram error: GPIO isr service is not installed</li><li>Weak Wi-Fi Signal</li><li>No IP Address in Arduino IDE Serial Monitor</li><li>Can’t open web server</li><li>The image lags/shows lots of latency</li></ul><p><a href="https://randomnerdtutorials.com/esp32-cam-projects-ebook/" target="_blank" rel="noreferrer"><img src="https://i0.wp.com/randomnerdtutorials.com/wp-content/uploads/2020/03/ESP32-CAM-eBook-334.jpg?fit=334%2C334&amp;quality=100&amp;strip=all&amp;ssl=1" alt=""></a></p><h3 id="ebook-build-esp32-cam-projects-using-arduino-ide" tabindex="-1"><a href="https://randomnerdtutorials.com/esp32-cam-projects-ebook/" target="_blank" rel="noreferrer">[eBook] Build ESP32-CAM Projects using Arduino IDE</a> <a class="header-anchor" href="#ebook-build-esp32-cam-projects-using-arduino-ide" aria-label="Permalink to &quot;[\\[eBook\\] Build ESP32-CAM Projects using Arduino IDE](https://randomnerdtutorials.com/esp32-cam-projects-ebook/)&quot;">​</a></h3><p>Learn how to program and build 17 projects with the ESP32-CAM using Arduino IDE <a href="https://randomnerdtutorials.com/esp32-cam-projects-ebook/" target="_blank" rel="noreferrer"><strong>DOWNLOAD »</strong></a></p><h3 id="wrapping-up" tabindex="-1">Wrapping Up <a class="header-anchor" href="#wrapping-up" aria-label="Permalink to &quot;Wrapping Up&quot;">​</a></h3><p>The ESP32-CAM provides an inexpensive way to build more advanced home automation projects that feature video, taking photos, and face recognition.</p><p>In this tutorial we’ve tested the CameraWebServer example to test the camera functionalities. Now, the idea is to modify the example or write a completely new code to build other projects. For example, <a href="https://randomnerdtutorials.com/esp32-cam-pir-motion-detector-photo-capture/" target="_blank" rel="noreferrer">take photos and save them to the microSD card when motion is detected</a>, <a href="https://randomnerdtutorials.com/esp32-cam-video-streaming-web-server-camera-home-assistant/" target="_blank" rel="noreferrer">integrate video streaming in your home automation platform (like Node-RED or Home Assistant)</a>, and much more.</p><p>We hope you’ve find this tutorial useful. If you don’t have an ESP32-CAM yet, you can <a href="https://makeradvisor.com/tools/esp32-cam/" target="_blank" rel="noreferrer">grab it here</a>.</p><p>If you like this project, you may also like other projects with the ESP32-CAM:</p><ul><li><a href="https://randomnerdtutorials.com/esp32-cam-video-streaming-web-server-camera-home-assistant/" target="_blank" rel="noreferrer">ESP32-CAM Video Streaming Web Server</a> (works with Home Assistant and Node-RED)</li><li><a href="https://randomnerdtutorials.com/esp32-cam-take-photo-save-microsd-card/" target="_blank" rel="noreferrer">ESP32-CAM Take Photo and Save to MicroSD Card</a></li><li><a href="https://randomnerdtutorials.com/esp32-cam-pir-motion-detector-photo-capture/" target="_blank" rel="noreferrer">ESP32-CAM PIR Motion Detector with Photo Capture (saves to microSD card)</a></li><li><a href="https://randomnerdtutorials.com/esp32-cam-take-photo-display-web-server/" target="_blank" rel="noreferrer">ESP32-CAM Take Photo and Display in Web Server</a></li><li><a href="https://randomnerdtutorials.com/esp32-cam-projects-ebook/" target="_blank" rel="noreferrer"><strong>Build ESP32-CAM Projects (eBook)</strong></a></li><li><a href="https://randomnerdtutorials.com/projects-esp32-cam/" target="_blank" rel="noreferrer"><strong>Read all our ESP32-CAM Projects, Tutorials and Guides</strong></a></li></ul>`,88)])])}const u=t(i,[["render",s]]);export{m as __pageData,u as default};
